#include<bits/stdc++.h>
using namespace std;
long long sum[200010];
long long lowbit(long long x)
{
    return (x&-x);
}
void update(long long x,long long v)
{
    for(long long i=x;i<=200000;i+=lowbit(i))
    {
        sum[i]=max(sum[i],v);
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans=max(ans,sum[i]);
    }
    return ans;
}
int main()
{
    long long m,d;
    scanf("%lld%lld",&m,&d);
    long long lst=0;
    long long p=0;
    while(m--)
    {
        char ch;
        long long x;
        cin>>ch>>x;
        if(ch=='Q')
        {
            x=p-x+1;
            printf("%lld\n",lst=query(200000-x+1));
        }
        else
        {
            p++;
            x+=lst;
            x%=d;
            update(200000-p+1,x);
        }
    }
    return 0;
}
